    27→public class PredicateDoc {
    28→
    29→    private static final class DocInfo {
    30→        final String predicateName;
    31→        final String overview;
    32→        final ConfigDef configDef;
    33→
    34→        private <P extends Predicate<?>> DocInfo(Class<P> predicateClass, String overview, ConfigDef configDef) {
    35→            this.predicateName = predicateClass.getName();
    36→            this.overview = overview;
    37→            this.configDef = configDef;
    38→        }
    39→    }
    40→
    41→    private static final List<DocInfo> PREDICATES = new Plugins(Collections.emptyMap()).predicates().stream()
    42→        .map(p -> {
    43→            try {
    44→                String overviewDoc = (String) p.pluginClass().getDeclaredField("OVERVIEW_DOC").get(null);
    45→                ConfigDef configDef = (ConfigDef) p.pluginClass().getDeclaredField("CONFIG_DEF").get(null);
    46→                return new DocInfo(p.pluginClass(), overviewDoc, configDef);
    47→            } catch (ReflectiveOperationException e) {
    48→                throw new RuntimeException("Predicate class " + p.pluginClass().getName() + " lacks either a `public static final String OVERVIEW_DOC` or `public static final ConfigDef CONFIG_DEF`");
    49→            }
    50→        })
    51→        .sorted(Comparator.comparing(docInfo -> docInfo.predicateName))
    52→        .toList();
